// Auto-generated by Stackpanel — do not edit manually.
// Runtime environment loader — decrypts generated per-app env payloads without
// depending on Node.js APIs. Suitable for Workers/edge runtimes where the SOPS
// key arrives via `process.env.SOPS_AGE_KEY` (or an explicit `secretKey` opt).

import * as Data from "effect/Data";
import * as Effect from "effect/Effect";
import { decryptSops } from "sops-age";
import { AVAILABLE_APP_ENVS } from "../embedded-data";
import type { AppEnvMap, AppName, EnvFor } from "./app-env-types";
import { loadGeneratedPayload } from "./generated-payloads/registry";

const AGE_SECRET_KEY_PREFIX = "AGE-SECRET-KEY-";
const payloadCache = new Map<string, Record<string, string>>();

export interface LoadEnvOptions {
  inject?: boolean;
  skipDecrypt?: boolean;
  secretKey?: string;
}

export class EnvLoadError extends Data.TaggedError("EnvLoadError")<{
  readonly message: string;
  readonly cause?: unknown;
}> {}

type SopsFileType = "json";

// ---------------------------------------------------------------------------
// Effect-native API. Returns Effects that the caller can compose; the
// Promise-returning wrappers below run them with the default runtime.
// ---------------------------------------------------------------------------

export const loadEnvEffect = <App extends string>(
  app: App,
  env: string,
  options: LoadEnvOptions = {},
): Effect.Effect<EnvFor<App>, EnvLoadError> =>
  (Effect.gen(function* () {
    const normalizedEnv = normalizeRuntimeEnv(env);
    const cacheKey = `${app}/${normalizedEnv}`;
    const cached = payloadCache.get(cacheKey);
    if (cached) {
      injectIntoProcessEnv(cached, options.inject);
      return cached;
    }

    const encryptedPayload = yield* Effect.tryPromise({
      try: () => loadGeneratedPayload(app, normalizedEnv),
      catch: (cause) =>
        new EnvLoadError({
          message: `Failed to load generated payload for ${app}/${normalizedEnv}.`,
          cause,
        }),
    });

    if (!encryptedPayload) {
      const knownEnvs = AVAILABLE_APP_ENVS[app] || [];
      const hint =
        knownEnvs.length > 0 ? ` Available environments: ${knownEnvs.join(", ")}.` : "";
      return yield* Effect.fail(
        new EnvLoadError({
          message: `Environment data not found for ${app}/${normalizedEnv}.${hint}`,
        }),
      );
    }

    const secretKeys = resolveRuntimeSecretKeys(options.secretKey);
    if (secretKeys.length === 0) {
      return yield* Effect.fail(
        new EnvLoadError({ message: missingKeyMaterialMessage() }),
      );
    }

    const decrypted = yield* decryptWithJsKeysEffect(
      encryptedPayload,
      "json",
      secretKeys,
    );
    const payload = normalizeEnvPayload(decrypted);
    payloadCache.set(cacheKey, payload);
    injectIntoProcessEnv(payload, options.inject);
    return payload;
  }) as Effect.Effect<EnvFor<App>, EnvLoadError>);

export const loadAppEnvEffect = loadEnvEffect;

// ---------------------------------------------------------------------------
// Promise-returning facade. Backward-compatible with the previous loader API.
// ---------------------------------------------------------------------------

export const loadEnv = <App extends string>(
  app: App,
  env: string,
  options: LoadEnvOptions = {},
): Promise<EnvFor<App>> =>
  Effect.runPromise(loadEnvEffect(app, env, options));

export const loadAppEnv = loadEnv;

export type { AppEnvMap, AppName, EnvFor };

// ---------------------------------------------------------------------------
// Internal Effect helpers
// ---------------------------------------------------------------------------

const decryptWithJsKeysEffect = (
  content: string,
  fileType: SopsFileType,
  secretKeys: ReadonlyArray<string>,
): Effect.Effect<Record<string, unknown>, EnvLoadError> =>
  Effect.gen(function* () {
    const errors: string[] = [];
    for (const key of secretKeys) {
      const result = yield* Effect.tryPromise({
        try: () => decryptSops(content, { fileType, secretKey: key }),
        catch: (error) => error,
      }).pipe(Effect.result);

      if (result._tag === "Success") {
        return (result.success as Record<string, unknown>) || {};
      }
      errors.push(formatError(result.failure));
    }

    return yield* Effect.fail(
      new EnvLoadError({
        message: `Failed to decrypt generated payload: ${errors.join("; ")}`,
      }),
    );
  });

// ---------------------------------------------------------------------------
// Pure helpers (also re-exported for the node loader and downstream callers)
// ---------------------------------------------------------------------------

export function normalizeRuntimeEnv(env: string): string {
  if (env === "production") return "prod";
  if (env === "development") return "dev";
  return env;
}

export function normalizeEnvPayload(
  payload: Record<string, unknown>,
): Record<string, string> {
  const result: Record<string, string> = {};
  for (const [key, value] of Object.entries(payload)) {
    if (typeof value === "string") {
      result[key] = value;
    } else if (typeof value === "number" || typeof value === "boolean") {
      result[key] = String(value);
    } else if (value == null) {
      result[key] = "";
    } else {
      result[key] = JSON.stringify(value);
    }
  }
  return result;
}

export function parseAgeSecretKeys(input?: string | null): string[] {
  if (!input) return [];
  const keys = input
    .split(/\r?\n/)
    .map((line) => line.trim())
    .filter((line) => line.startsWith(AGE_SECRET_KEY_PREFIX));
  return [...new Set(keys)];
}

function resolveRuntimeSecretKeys(explicitSecretKey?: string): string[] {
  if (explicitSecretKey) return parseAgeSecretKeys(explicitSecretKey);
  const envObject = getProcessEnv();
  return parseAgeSecretKeys(envObject.SOPS_AGE_KEY);
}

function injectIntoProcessEnv(payload: Record<string, string>, inject = true) {
  if (inject === false) return;
  const processEnv = maybeProcessEnv();
  if (processEnv) Object.assign(processEnv, payload);
}

function maybeProcessEnv(): Record<string, string | undefined> | null {
  if (typeof process === "undefined") return null;
  return process.env as Record<string, string | undefined>;
}

function getProcessEnv(): Record<string, string | undefined> {
  return maybeProcessEnv() ?? {};
}

function missingKeyMaterialMessage(): string {
  return "No SOPS decryption key is configured. Set SOPS_AGE_KEY or pass a secretKey option.";
}

function formatError(error: unknown): string {
  if (error instanceof Error) return error.message;
  return String(error);
}

// Re-exported so the Node loader (and downstream callers) can read the
// AGE prefix without redefining it.
export { AGE_SECRET_KEY_PREFIX };
